<?php require_once __DIR__ . '/app/auth.php'; require_login(); csrf_check(); $pdo=db();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $action=$_POST['action']??'save';
  if($action==='delete'){ $pdo->prepare('DELETE FROM payments WHERE id=?')->execute([(int)$_POST['id']]); redirect('payments.php'); }
  $customer=(int)$_POST['customer_id']; $id=(int)($_POST['id']??0);
  $st=$pdo->prepare('SELECT c.*,p.price FROM customers c LEFT JOIN packages p ON p.id=c.package_id WHERE c.id=?');$st->execute([$customer]);$c=$st->fetch();
  if($c){ $data=[$customer,trim($_POST['invoice_month']),(int)$_POST['amount'],trim($_POST['paid_at']),trim($_POST['method']),$_SESSION['user']['name'],trim($_POST['notes'])];
    if($id){$data[]=$id;$pdo->prepare('UPDATE payments SET customer_id=?,invoice_month=?,amount=?,paid_at=?,method=?,received_by=?,notes=? WHERE id=?')->execute($data);} else {$insertData=array_merge([payment_code()],$data);$pdo->prepare('INSERT INTO payments(payment_code,customer_id,invoice_month,amount,paid_at,method,received_by,notes) VALUES(?,?,?,?,?,?,?,?)')->execute($insertData);}}
  redirect('payments.php');
}
require_once __DIR__ . '/app/layout.php'; $selected=(int)($_GET['customer_id']??0); $edit=null; if(isset($_GET['edit'])){$st=$pdo->prepare('SELECT * FROM payments WHERE id=?');$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(); if($edit)$selected=(int)$edit['customer_id'];}
$customers=$pdo->query('SELECT c.*,p.price,p.name package_name FROM customers c LEFT JOIN packages p ON p.id=c.package_id ORDER BY c.name ASC')->fetchAll(); $rows=$pdo->query('SELECT pay.*,c.name customer_name,c.customer_code FROM payments pay JOIN customers c ON c.id=pay.customer_id ORDER BY pay.paid_at DESC,pay.id DESC LIMIT 80')->fetchAll(); render_header('Pembayaran'); ?>
<div class="grid-2"><form class="card form-card" method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=e($edit['id']??0)?>"><div class="panel-title"><h2><?=$edit?'Edit':'Input'?> Pembayaran</h2><?php if($edit):?><a class="btn soft xs" href="payments.php">Batal Edit</a><?php endif;?></div><div class="form-grid"><div class="field"><label>Pelanggan</label><select name="customer_id" id="customerSelect" required onchange="setAmount()"><option value="">Pilih pelanggan</option><?php foreach($customers as $c):?><option data-price="<?=e($c['price']??0)?>" value="<?=$c['id']?>" <?=$selected===$c['id']?'selected':''?>><?=e($c['customer_code'].' - '.$c['name'].' / '.$c['package_name'])?></option><?php endforeach;?></select></div><div class="field"><label>Bulan Tagihan</label><input name="invoice_month" type="month" value="<?=e($edit['invoice_month']??current_month())?>" required></div><div class="field"><label>Nominal</label><input id="amount" name="amount" type="number" required value="<?=e($edit['amount']??'')?>"></div><div class="field"><label>Tanggal Bayar</label><input name="paid_at" type="date" value="<?=e($edit['paid_at']??date('Y-m-d'))?>" required></div><div class="field"><label>Metode</label><select name="method"><?php foreach(['Cash','Transfer','QRIS','Lainnya'] as $m):?><option <?=($edit&&$edit['method']===$m)?'selected':''?>><?=$m?></option><?php endforeach;?></select></div><div class="field"><label>Catatan</label><input name="notes" placeholder="Opsional" value="<?=e($edit['notes']??'')?>"></div></div><button class="btn primary mt-5"><?=$edit?'Update':'Simpan'?> Pembayaran</button></form><div class="card"><div class="panel-title"><h2>Riwayat Pembayaran</h2></div><div class="table-wrap"><table class="responsive"><thead><tr><th>Tanggal</th><th>Pelanggan</th><th>Bulan</th><th>Nominal</th><th>Metode</th><th>Aksi</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td data-label="Tanggal"><?=e($r['paid_at'])?><br><small class="text-slate-500"><?=e($r['payment_code'])?></small></td><td data-label="Pelanggan"><b><?=e($r['customer_code'])?></b><br><?=e($r['customer_name'])?></td><td data-label="Bulan"><?=e($r['invoice_month'])?></td><td data-label="Nominal"><b><?=rupiah($r['amount'])?></b></td><td data-label="Metode"><span class="pill blue"><?=e($r['method'])?></span></td><td data-label="Aksi"><div class="table-actions"><a class="btn soft xs" href="payments.php?edit=<?=$r['id']?>">Edit</a><a class="btn primary xs" href="receipt.php?id=<?=$r['id']?>" target="_blank">Kwitansi</a><form method="post" onsubmit="return confirm('Hapus pembayaran ini?')"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=$r['id']?>"><button class="btn red xs">Hapus</button></form></div></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="6">Belum ada pembayaran.</td></tr><?php endif;?></tbody></table></div></div></div><script>function setAmount(){const a=document.querySelector('#amount'); if(a.value) return; const o=document.querySelector('#customerSelect').selectedOptions[0];if(o&&o.dataset.price)a.value=o.dataset.price}setAmount()</script><?php render_footer(); ?>
